    override fun onStartCommand(intent: Intent?, flags: Int, startId: Int): Int {
        Log.i(TAG, "onStartCommand received: action=${intent?.action}")

        if (intent == null) {
            Log.w(TAG, "Received null intent, ignoring")
            return START_STICKY
        }

        when (intent.action) {
            ACTION_CANCEL_TASKS -> {
                handleCancelTasks(intent)
            }
            ACTION_SYNC_DATA, ACTION_CLEANUP, ACTION_FULL_OPTIMIZATION -> {
                val taskInfo = parseTaskInfo(intent)
                if (taskInfo != null) {
                    enqueueTask(taskInfo)
                } else {
                    Log.e(TAG, "Failed to parse task info from intent")
                }
            }
            else -> {
                Log.w(TAG, "Unknown action: ${intent.action}")
            }
        }

        return START_STICKY
    }

    override fun onBind(intent: Intent?): IBinder? {
