    private fun parseTaskInfo(intent: Intent): TaskInfo? {
        val action = intent.action ?: return null
        val taskId = intent.getStringExtra(EXTRA_TASK_ID)
            ?: UUID.randomUUID().toString()

        val extras = mutableMapOf<String, Any?>()
        extras[EXTRA_SYNC_SOURCE] = intent.getStringExtra(EXTRA_SYNC_SOURCE)
        extras[EXTRA_SYNC_TARGET] = intent.getStringExtra(EXTRA_SYNC_TARGET)
        extras[EXTRA_CLEANUP_TYPE] = intent.getStringExtra(EXTRA_CLEANUP_TYPE) ?: CLEANUP_ALL
        extras[EXTRA_CLEANUP_OLDER_THAN_DAYS] = intent.getIntExtra(EXTRA_CLEANUP_OLDER_THAN_DAYS, 30)

        val priority = intent.getIntExtra(EXTRA_PRIORITY, PRIORITY_NORMAL)
        val callbackAction = intent.getStringExtra(EXTRA_CALLBACK_ACTION)
        val callbackPackage = intent.getStringExtra(EXTRA_CALLBACK_PACKAGE)
        val dryRun = intent.getBooleanExtra(EXTRA_DRY_RUN, false)

        return TaskInfo(
            taskId = taskId,
            action = action,
            priority = priority,
            extras = extras,
            callbackAction = callbackAction,
            callbackPackage = callbackPackage,
            dryRun = dryRun
        )
    }

    private fun enqueueTask(taskInfo: TaskInfo) {
        Log.i(TAG, "Enqueueing task: ${taskInfo.taskId}, action: ${taskInfo.action}, priority: ${taskInfo.priority}")
        taskQueue.add(taskInfo)
        processNextTask()
    }

    @Synchronized
    private fun processNextTask() {
        if (isProcessing && taskQueue.isEmpty()) {
            return
        }

        // Sort by priority (higher first), then by timestamp (older first)
        val sortedTasks = taskQueue.sortedWith(
            compareByDescending<TaskInfo> { it.priority }.thenBy { it.timestamp }
        )
        taskQueue.clear()
        taskQueue.addAll(sortedTasks)

        val task = taskQueue.poll() ?: run {
            if (activeTasks.isEmpty()) {
                updateNotification("Idle - waiting for tasks")
            }
            return
        }

        isProcessing = true
        updateNotification("Processing task: ${task.taskId}")

        val job = serviceScope.launch {
            try {
                val result = executeTask(task)
                sendResultCallback(task, result)
                logTaskResult(result)
            } catch (e: CancellationException) {
                Log.i(TAG, "Task ${task.taskId} was cancelled")
                val result = TaskResult(
                    taskId = task.taskId,
                    resultCode = RESULT_CANCELLED,
                    message = "Task was cancelled"
                )
                sendResultCallback(task, result)
            } catch (e: Exception) {
                Log.e(TAG, "Task ${task.taskId} failed with exception", e)
                val result = TaskResult(
                    taskId = task.taskId,
                    resultCode = RESULT_FAILURE,
                    message = "Task failed: ${e.message}"
                )
                sendResultCallback(task, result)
            } finally {
                activeTasks.remove(task.taskId)
                isProcessing = false
                // Process next task in queue
                processNextTask()
            }
        }

        activeTasks[task.taskId] = job
    }

    private suspend fun executeTask(task: TaskInfo): TaskResult {
        return when (task.action) {
            ACTION_SYNC_DATA -> executeSyncData(task)
            ACTION_CLEANUP -> executeCleanup(task)
            ACTION_FULL_OPTIMIZATION -> executeFullOptimization(task)
            else -> TaskResult(
                taskId = task.taskId,
                resultCode = RESULT_FAILURE,
                message = "Unknown action: ${task.action}"
            )
        }
    }

    private suspend fun executeSyncData(task: TaskInfo): TaskResult {
        Log.i(TAG, "Executing data sync for task: ${task.taskId}")

        val source = task.extras[EXTRA_SYNC_SOURCE] as? String ?: "default_source"
        val target = task.extras[EXTRA_SYNC_TARGET] as? String ?: "default_target"
        val dryRun = task.dryRun

        var recordsSynced = 0
        val totalRecords = 100 // Simulated record count

        return withContext(Dispatchers.IO) {
            try {
                Log.i(TAG, "Syncing from $source to $target (dryRun=$dryRun)")

