                    }
                }

                // Phase 4: Verify sync
                updateNotification("Task ${task.taskId}: Verifying sync...")
                delay(300) // Simulate verification

                val prefix = if (dryRun) "[DRY RUN] " else ""
                TaskResult(
                    taskId = task.taskId,
                    resultCode = RESULT_SUCCESS,
                    message = "${prefix}Successfully synced $recordsSynced records from $source to $target",
                    recordsSynced = recordsSynced
                )
            } catch (e: CancellationException) {
                throw e
            } catch (e: Exception) {
                TaskResult(
                    taskId = task.taskId,
                    resultCode = RESULT_PARTIAL,
