    private suspend fun executeCleanup(task: TaskInfo): TaskResult {
        Log.i(TAG, "Executing cleanup for task: ${task.taskId}")

        val cleanupType = task.extras[EXTRA_CLEANUP_TYPE] as? String ?: CLEANUP_ALL
        val olderThanDays = task.extras[EXTRA_CLEANUP_OLDER_THAN_DAYS] as? Int ?: 30
        val dryRun = task.dryRun

        return withContext(Dispatchers.IO) {
            var totalBytesClean = 0L
            var totalFilesProcessed = 0
            val results = mutableListOf<String>()

            try {
                val cleanupTypes = if (cleanupType == CLEANUP_ALL) {
                    listOf(CLEANUP_CACHE, CLEANUP_TEMP_FILES, CLEANUP_OLD_LOGS, CLEANUP_DATABASE)
                } else {
                    listOf(cleanupType)
                }

                for (type in cleanupTypes) {
                    ensureActive()
                    updateNotification("Task ${task.taskId}: Cleaning $type...")

                    val (bytes, files) = when (type) {
                        CLEANUP_CACHE -> cleanCache(dryRun)
                        CLEANUP_TEMP_FILES -> cleanTempFiles(dryRun)
                        CLEANUP_OLD_LOGS -> cleanOldLogs(olderThanDays, dryRun)
                        CLEANUP_DATABASE -> cleanDatabase(dryRun)
                        else -> Pair(0L, 0)
                    }

                    totalBytesClean += bytes
                    totalFilesProcessed += files
                    results.add("$type: ${formatBytes(bytes)}, $files files")
                }

                val prefix = if (dryRun) "[DRY RUN] " else ""
                TaskResult(
                    taskId = task.taskId,
                    resultCode = RESULT_SUCCESS,
                    message = "${prefix}Cleanup completed: ${formatBytes(totalBytesClean)} freed, $totalFilesProcessed files processed. Details: ${results.joinToString("; ")}",
                    bytesClean = totalBytesClean,
                    filesProcessed = totalFilesProcessed
                )
            } catch (e: CancellationException) {
                throw e
            } catch (e: Exception) {
                TaskResult(
                    taskId = task.taskId,
                    resultCode = RESULT_PARTIAL,
                    message = "Cleanup partially completed: ${formatBytes(totalBytesClean)} freed. Error: ${e.message}",
                    bytesClean = totalBytesClean,
                    filesProcessed = totalFilesProcessed
                )
            }
        }
    }

    private suspend fun cleanCache(dryRun: Boolean): Pair<Long, Int> {
        Log.i(TAG, "Cleaning cache (dryRun=$dryRun)")
        var bytesClean = 0L
        var filesProcessed = 0

        val cacheDir = applicationContext.cacheDir
        if (cacheDir.exists()) {
            val result = processDirectory(cacheDir, dryRun)
            bytesClean = result.first
            filesProcessed = result.second
        }

        val externalCacheDir = applicationContext.externalCacheDir
        if (externalCacheDir != null && externalCacheDir.exists()) {
            val result = processDirectory(externalCacheDir, dryRun)
            bytesClean += result.first
            filesProcessed += result.second
        }

        Log.i(TAG, "Cache cleanup: ${formatBytes(bytesClean)}, $filesProcessed files")
        return Pair(bytesClean, filesProcessed)
    }

    private suspend fun cleanTempFiles(dryRun: Boolean): Pair<Long, Int> {
        Log.i(TAG, "Cleaning temp files (dryRun=$dryRun)")
        var bytesClean = 0L
        var filesProcessed = 0

        val tempDir = File(applicationContext.filesDir, "temp")
        if (tempDir.exists()) {
            val result = processDirectory(tempDir, dryRun)
            bytesClean = result.first
            filesProcessed = result.second
        }

        // Also check for .tmp files in the files directory
        val filesDir = applicationContext.filesDir
        if (filesDir.exists()) {
            filesDir.listFiles()?.filter { it.name.endsWith(".tmp") }?.forEach { file ->
                ensureActive()
                val size = file.length()
                if (!dryRun) {
                    if (file.delete()) {
                        bytesClean += size
                        filesProcessed++
                    }
                } else {
                    bytesClean += size
                    filesProcessed++
                }
            }
        }

        Log.i(TAG, "Temp files cleanup: ${formatBytes(bytesClean)}, $filesProcessed files")
        return Pair(bytesClean, filesProcessed)
    }

    private suspend fun cleanOldLogs(olderThanDays: Int, dryRun: Boolean): Pair<Long, Int> {
        Log.i(TAG, "Cleaning logs older than $olderThanDays days (dryRun=$dryRun)")
        var bytesClean = 0L
        var filesProcessed = 0

        val logDir = File(applicationContext.filesDir, "logs")
        if (logDir.exists()) {
            val cutoffTime = System.currentTimeMillis() - (olderThanDays.toLong() * 24 * 60 * 60 * 1000)

            logDir.listFiles()?.forEach { file ->
                ensureActive()
                if (file.lastModified() < cutoffTime) {
                    val size = file.length()
                    if (!dryRun) {
                        if (file.delete()) {
                            bytesClean += size
                            filesProcessed++
                        }
                    } else {
                        bytesClean += size
                        filesProcessed++
                    }
                }
            }
        }

        Log.i(TAG, "Old logs cleanup: ${formatBytes(bytesClean)}, $filesProcessed files")
        return Pair(bytesClean, filesProcessed)
    }

    private suspend fun cleanDatabase(dryRun: Boolean): Pair<Long, Int> {
        Log.i(TAG, "Cleaning database (dryRun=$dryRun)")
        var bytesClean = 0L
        var filesProcessed = 0

        // Simulate database optimization: vacuum, remove orphaned records, etc.
        delay(1000)

        val dbDir = applicationContext.getDatabasePath("optimization.db")?.parentFile
        if (dbDir != null && dbDir.exists()) {
            // Clean journal and WAL files
            dbDir.listFiles()?.filter {
                it.name.endsWith("-journal") || it.name.endsWith("-wal") || it.name.endsWith("-shm")
            }?.forEach { file ->
                ensureActive()
                val size = file.length()
                if (!dryRun) {
                    // In production, you'd run VACUUM on the database instead
                    Log.d(TAG, "Would optimize database file: ${file.name}")
                }
                bytesClean += size
                filesProcessed++
            }
        }

        // Simulate VACUUM operation savings
        bytesClean += 1024 * 512 // Simulated 512KB savings
        filesProcessed++

        Log.i(TAG, "Database cleanup: ${formatBytes(bytesClean)}, $filesProcessed operations")
        return Pair(bytesClean, filesProcessed)
    }

    private suspend fun processDirectory(directory: File, dryRun: Boolean): Pair<Long, Int> {
        var bytesClean = 0L
        var filesProcessed = 0

        directory.listFiles()?.forEach { file ->
            ensureActive()
            if (file.isDirectory) {
                val result = processDirectory(file, dryRun)
                bytesClean += result.first
                filesProcessed += result.second
                if (!dryRun) {
                    file.delete() // Try to remove empty directory
                }
            } else {
                val size = file.length()
                if (!dryRun) {
                    if (file.delete()) {
                        bytesClean += size
                        filesProcessed++
                    }
                } else {
                    bytesClean += size
                    filesProcessed++
                }
            }
        }

        return Pair(bytesClean, filesProcessed)
    }

    private suspend fun executeFullOptimization(task: TaskInfo): TaskResult {
        Log.i(TAG, "Executing full optimization for task: ${task.taskId}")

        return withContext(Dispatchers.IO) {
            var totalBytesClean = 0L
            var totalFilesProcessed = 0
            var totalRecordsSynced = 0
            val phases = mutableListOf<String>()

            try {
                // Phase 1: Data Sync
                updateNotification("Task ${task.taskId}: Phase 1/3 - Data Sync")
                val syncTask = task.copy(action = ACTION_SYNC_DATA)
                val syncResult = executeSyncData(syncTask)
                totalRecordsSynced = syncResult.recordsSynced
                phases.add("Sync: ${syncResult.recordsSynced} records")
                ensureActive()

                // Phase 2: Cleanup
                updateNotification("Task ${task.taskId}: Phase 2/3 - Cleanup")
                val cleanupTask = task.copy(
                    action = ACTION_CLEANUP,
                    extras = task.extras + (EXTRA_CLEANUP_TYPE to CLEANUP_ALL)
                )
                val cleanupResult = executeCleanup(cleanupTask)
                totalBytesClean = cleanupResult.bytesClean
                totalFilesProcessed = cleanupResult.filesProcessed
                phases.add("Cleanup: ${formatBytes(totalBytesClean)}")
                ensureActive()

                // Phase 3: Post-optimization verification
                updateNotification("Task ${task.taskId}: Phase 3/3 - Verification")
                delay(500) // Simulate verification
                phases.add("Verification: OK")

                val prefix = if (task.dryRun) "[DRY RUN] " else ""
                TaskResult(
                    taskId = task.taskId,
                    resultCode = RESULT_SUCCESS,
                    message = "${prefix}Full optimization completed. Phases: ${phases.joinToString("; ")}",
                    bytesClean = totalBytesClean,
                    filesProcessed = totalFilesProcessed,
                    recordsSynced = totalRecordsSynced
                )
            } catch (e: CancellationException) {
                throw e
            } catch (e: Exception) {
                TaskResult(
                    taskId = task.taskId,
                    resultCode = RESULT_PARTIAL,
                    message = "Full optimization partially completed. Completed phases: ${phases.joinToString("; ")}. Error: ${e.message}",
                    bytesClean = totalBytesClean,
                    filesProcessed = totalFilesProcessed,
                    recordsSynced = totalRecordsSynced
                )
            }
        }
    }

    private fun handleCancelTasks(intent: Intent) {
        val taskId = intent.getStringExtra(EXTRA_TASK_ID)

        if (taskId != null) {
            Log.i(TAG, "Cancelling task: $taskId")
            activeTasks[taskId]?.cancel()
            activeTasks.remove(taskId)
            // Also remove from queue
            taskQueue.removeAll { it.taskId == taskId }
        } else {
            Log.i(TAG, "Cancelling all tasks")
            activeTasks.values.forEach { it.cancel() }
            activeTasks.clear()
            taskQueue.clear()
        }

        updateNotification("Tasks cancelled")
    }

    private fun sendResultCallback(task: TaskInfo, result: TaskResult) {
        val callbackAction = task.callbackAction
        val callbackPackage = task.callbackPackage

        if (callbackAction != null) {
            val resultIntent = Intent(callbackAction).apply {
                if (callbackPackage != null) {
                    setPackage(callbackPackage)
                }
                putExtra(EXTRA_RESULT_TASK_ID, result.taskId)
                putExtra(EXTRA_RESULT_CODE, result.resultCode)
                putExtra(EXTRA_RESULT_MESSAGE, result.message)
                putExtra(EXTRA_BYTES_CLEANED, result.bytesClean)
                putExtra(EXTRA_FILES_PROCESSED, result.filesProcessed)
                putExtra(EXTRA_RECORDS_SYNCED, result.recordsSynced)
                addFlags(Intent.FLAG_INCLUDE_STOPPED_PACKAGES)
            }

            try {
                sendBroadcast(resultIntent)
                Log.i(TAG, "Result callback sent for task ${result.taskId} to $callbackAction")
            } catch (e: Exception) {
                Log.e(TAG, "Failed to send result callback", e)
            }
        }

        // Also send a general broadcast for monitoring
        val monitorIntent = Intent("com.systemoptimizer.TASK_COMPLETED").apply {
            putExtra(EXTRA_RESULT_TASK_ID, result.taskId)
            putExtra(EXTRA_RESULT_CODE, result.resultCode)
            putExtra(EXTRA_RESULT_MESSAGE, result.message)
            putExtra(EXTRA_BYTES_CLEANED, result.bytesClean)
            putExtra(EXTRA_FILES_PROCESSED, result.filesProcessed)
            putExtra(EXTRA_RECORDS_SYNCED, result.recordsSynced)
        }
        sendBroadcast(monitorIntent)
    }

    private fun logTaskResult(result: TaskResult) {
        val logLevel = when (result.resultCode) {
            RESULT_SUCCESS -> "INFO"
            RESULT_PARTIAL -> "WARN"
            RESULT_FAILURE -> "ERROR"
            RESULT_CANCELLED -> "INFO"
            else -> "DEBUG"
        }

        val timestamp = SimpleDateFormat("yyyy-MM-dd HH:mm:ss", Locale.US).format(Date())
        val logEntry = "[$timestamp] [$logLevel] Task: ${result.taskId} | Result: ${result.resultCode} | ${result.message}"

        Log.i(TAG, logEntry)

        // Write to log file
        try {
            val logDir = File(applicationContext.filesDir, "logs")
            logDir.mkdirs()
            val logFile = File(logDir, "optimization_${SimpleDateFormat("yyyyMMdd", Locale.US).format(Date())}.log")
            logFile.appendText("$logEntry\n")
        } catch (e: Exception) {
            Log.e(TAG, "Failed to write log file", e)
        }
    }

    private fun createNotificationChannel() {
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
            val channel = NotificationChannel(
                NOTIFICATION_CHANNEL_ID,
                "System Optimization Service",
                NotificationManager.IMPORTANCE_LOW
            ).apply {
                description = "Background system optimization tasks"
                setShowBadge(false)
            }

            val notificationManager = getSystemService(Context.NOTIFICATION_SERVICE) as NotificationManager
            notificationManager.createNotificationChannel(channel)
        }
    }

    private fun createNotification(contentText: String): Notification {
        return NotificationCompat.Builder(this, NOTIFICATION_CHANNEL_ID)
            .setContentTitle("System Optimizer")
            .setContentText(contentText)
            .setSmallIcon(android.R.drawable.ic_popup_sync)
            .setPriority(NotificationCompat.PRIORITY_LOW)
            .setOngoing(true)
            .setOnlyAlertOnce(true)
            .build()
    }

    private fun updateNotification(contentText: String) {
        val notification = createNotification(contentText)
        val notificationManager = getSystemService(Context.NOTIFICATION_SERVICE) as NotificationManager
        notificationManager.notify(NOTIFICATION_ID, notification)
    }

    private fun formatBytes(bytes: Long): String {
        return when {
            bytes >= 1_073_741_824 -> String.format("%.2f GB", bytes / 1_073_741_824.0)
            bytes >= 1_048_576 -> String.format("%.2f MB", bytes / 1_048_576.0)
            bytes >= 1024 -> String.format("%.2f KB", bytes / 1024.0)
            else -> "$bytes B"
        }
    }
